"use client";

import { useState } from "react";
import { Plus, Trash2 } from "lucide-react";
import {
  Popover,
  PopoverContent,
  PopoverTrigger,
} from "@/components/ui/popover";
import {
  Dialog,
  DialogContent,
  DialogFooter,
  DialogHeader,
  DialogTitle,
  DialogTrigger,
} from "@/components/ui/dialog";
import { Card } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { AvatarStack } from "@/components/ui/avatar-stack";
import { cn } from "@/lib/utils";

export interface CalendarDay {
  label: string;
  date: string;
}

export interface CalendarEvent {
  id: string;
  day: number;
  row: number;
  title: string;
  subtitle: string;
  dark?: boolean;
  avatars?: Array<{ src?: string; alt: string; fallback: string }>;
}

export interface CalendarCardProps {
  monthLabel: string;
  prevLabel: string;
  nextLabel: string;
  days: CalendarDay[];
  times: string[];
  events: CalendarEvent[];
  todayIndex?: number;
  weekOffset?: number;
  onPrevWeek?: () => void;
  onNextWeek?: () => void;
  onCreateEvent?: (day: number, row: number, title: string, start: string, end: string) => void;
  onDeleteEvent?: (id: string) => void;
  className?: string;
}

function CalendarCell({
  hasEvent,
  event,
  onCreate,
  onDelete,
}: {
  hasEvent: boolean;
  event?: CalendarEvent;
  onCreate?: (title: string, start: string, end: string) => void;
  onDelete?: (id: string) => void;
}) {
  const [createOpen, setCreateOpen] = useState(false);
  const [title, setTitle] = useState("");
  const [start, setStart] = useState("09:00");
  const [end, setEnd] = useState("10:00");

  return (
    <div className="relative min-h-[56px] border-t border-dashed border-neutral-200">
      {hasEvent && event ? (
        <Popover>
          <PopoverTrigger asChild>
            <button
              type="button"
              className={cn(
                "absolute left-1 right-1 top-2 z-10 flex items-center justify-between gap-2 rounded-2xl px-3 py-2 text-left transition-shadow hover:shadow-card-md lg:right-[-180px]",
                event.dark ? "bg-neutral-900 text-white" : "bg-white shadow-card",
              )}
            >
              <div className="min-w-0">
                <p
                  className={cn(
                    "truncate text-xs font-semibold sm:text-sm",
                    event.dark ? "text-white" : "text-neutral-900",
                  )}
                >
                  {event.title}
                </p>
                <p
                  className={cn(
                    "truncate text-[10px] sm:text-xs",
                    event.dark ? "text-white/60" : "text-neutral-500",
                  )}
                >
                  {event.subtitle}
                </p>
              </div>
              {event.avatars && event.avatars.length > 0 && (
                <div className="hidden sm:block">
                  <AvatarStack avatars={event.avatars} />
                </div>
              )}
            </button>
          </PopoverTrigger>
          <PopoverContent className="w-64">
            <div className="space-y-2">
              <p className="text-sm font-semibold text-neutral-900">{event.title}</p>
              <p className="text-xs text-neutral-500">{event.subtitle}</p>
              <Button
                size="sm"
                variant="destructive"
                className="w-full"
                onClick={() => onDelete?.(event.id)}
              >
                <Trash2 className="mr-1 h-3 w-3" /> Delete
              </Button>
            </div>
          </PopoverContent>
        </Popover>
      ) : (
        <Dialog open={createOpen} onOpenChange={setCreateOpen}>
          <DialogTrigger asChild>
            <button
              type="button"
              aria-label="Add event"
              className="absolute inset-0 m-1 flex items-center justify-center rounded-xl opacity-0 transition-opacity hover:bg-neutral-100/50 hover:opacity-100"
            >
              <Plus className="h-4 w-4 text-neutral-400" />
            </button>
          </DialogTrigger>
          <DialogContent>
            <DialogHeader>
              <DialogTitle>New event</DialogTitle>
            </DialogHeader>
            <div className="space-y-3">
              <div>
                <Label htmlFor="ev-title">Event name</Label>
                <Input
                  id="ev-title"
                  value={title}
                  onChange={(e) => setTitle(e.target.value)}
                  placeholder="Event name"
                />
              </div>
              <div className="grid grid-cols-2 gap-3">
                <div>
                  <Label htmlFor="ev-start">Start</Label>
                  <Input
                    id="ev-start"
                    type="time"
                    value={start}
                    onChange={(e) => setStart(e.target.value)}
                  />
                </div>
                <div>
                  <Label htmlFor="ev-end">End</Label>
                  <Input id="ev-end" type="time" value={end} onChange={(e) => setEnd(e.target.value)} />
                </div>
              </div>
            </div>
            <DialogFooter>
              <Button
                onClick={() => {
                  if (!title.trim()) return;
                  onCreate?.(title.trim(), start, end);
                  setTitle("");
                  setCreateOpen(false);
                }}
              >
                Add
              </Button>
            </DialogFooter>
          </DialogContent>
        </Dialog>
      )}
    </div>
  );
}

function CalendarCard({
  monthLabel,
  prevLabel,
  nextLabel,
  days,
  times,
  events,
  todayIndex,
  weekOffset = 0,
  onPrevWeek,
  onNextWeek,
  onCreateEvent,
  onDeleteEvent,
  className,
}: CalendarCardProps) {
  return (
    <Card variant="glass" className={cn("flex h-full flex-col gap-4 p-5", className)}>
      <div className="flex items-center justify-between gap-2">
        <button
          type="button"
          onClick={onPrevWeek}
          className="min-h-[36px] rounded-full bg-white px-4 py-2 text-xs font-medium text-neutral-500 shadow-card transition-colors hover:bg-neutral-50"
        >
          {prevLabel}
        </button>
        <h3 className="text-base font-semibold text-neutral-900 sm:text-lg">{monthLabel}</h3>
        <button
          type="button"
          onClick={onNextWeek}
          className="min-h-[36px] rounded-full bg-white px-4 py-2 text-xs font-medium text-neutral-500 shadow-card transition-colors hover:bg-neutral-50"
        >
          {nextLabel}
        </button>
      </div>

      <div className="grid grid-cols-[48px_repeat(6,1fr)] gap-x-1 overflow-x-auto sm:grid-cols-[64px_repeat(6,1fr)] sm:gap-x-2">
        <div />
        {days.map((day, i) => {
          const isToday = weekOffset === 0 && todayIndex === i;
          return (
            <div
              key={`${day.label}-${day.date}`}
              className={cn("flex flex-col items-center rounded-xl py-2", isToday && "bg-neutral-900/5")}
            >
              <span className={cn("text-xs font-medium", isToday ? "text-neutral-900" : "text-neutral-500")}>
                {day.label}
              </span>
              <span className="text-sm font-semibold text-neutral-900">{day.date}</span>
            </div>
          );
        })}

        {times.map((time, rowIdx) => (
          <div key={time} className="contents">
            <div className="border-t border-dashed border-neutral-200 py-4 pr-2 text-[10px] font-medium text-neutral-500 sm:text-xs">
              {time}
            </div>
            {days.map((day, colIdx) => {
              const ev = events.find((e) => e.day === colIdx && e.row === rowIdx);
              return (
                <CalendarCell
                  key={`${day.label}-${time}`}
                  hasEvent={!!ev}
                  event={ev}
                  onCreate={(title, start, end) => onCreateEvent?.(colIdx, rowIdx, title, start, end)}
                  onDelete={onDeleteEvent}
                />
              );
            })}
          </div>
        ))}
      </div>
    </Card>
  );
}

export { CalendarCard };

import * as React from "react";
import * as PopoverPrimitive from "@radix-ui/react-popover";
import { cva, type VariantProps } from "class-variance-authority";

import { cn } from "@/lib/utils";

const popoverContentVariants = cva(
  "z-50 w-72 outline-none data-[state=open]:animate-in data-[state=closed]:animate-out data-[state=closed]:fade-out-0 data-[state=open]:fade-in-0 data-[state=closed]:zoom-out-95 data-[state=open]:zoom-in-95 data-[side=bottom]:slide-in-from-top-2 data-[side=left]:slide-in-from-right-2 data-[side=right]:slide-in-from-left-2 data-[side=top]:slide-in-from-bottom-2 origin-(--radix-popover-content-transform-origin)",
  {
    variants: {
      variant: {
        default: "rounded-2xl border bg-popover p-4 text-popover-foreground shadow-card-md",
        dark: "rounded-2xl border border-white/5 bg-brand-ink p-0 text-white shadow-card-dark",
      },
    },
    defaultVariants: { variant: "default" },
  },
);

const Popover = PopoverPrimitive.Root;
const PopoverTrigger = PopoverPrimitive.Trigger;
const PopoverAnchor = PopoverPrimitive.Anchor;

export interface PopoverContentProps
  extends React.ComponentPropsWithoutRef<typeof PopoverPrimitive.Content>,
    VariantProps<typeof popoverContentVariants> {}

const PopoverContent = React.forwardRef<
  React.ElementRef<typeof PopoverPrimitive.Content>,
  PopoverContentProps
>(({ className, variant, align = "center", sideOffset = 4, ...props }, ref) => (
  <PopoverPrimitive.Portal>
    <PopoverPrimitive.Content
      ref={ref}
      align={align}
      sideOffset={sideOffset}
      className={cn(popoverContentVariants({ variant }), className)}
      {...props}
    />
  </PopoverPrimitive.Portal>
));
PopoverContent.displayName = PopoverPrimitive.Content.displayName;

export { Popover, PopoverTrigger, PopoverContent, PopoverAnchor, popoverContentVariants };

"use client";

import * as React from "react";
import * as DialogPrimitive from "@radix-ui/react-dialog";
import { X } from "lucide-react";

import { cn } from "@/lib/utils";

const Dialog = DialogPrimitive.Root;

const DialogTrigger = DialogPrimitive.Trigger;

const DialogPortal = DialogPrimitive.Portal;

const DialogClose = DialogPrimitive.Close;

const DialogOverlay = React.forwardRef<
  React.ElementRef<typeof DialogPrimitive.Overlay>,
  React.ComponentPropsWithoutRef<typeof DialogPrimitive.Overlay>
>(({ className, ...props }, ref) => (
  <DialogPrimitive.Overlay
    ref={ref}
    className={cn(
      "fixed inset-0 z-50 bg-black/80  data-[state=open]:animate-in data-[state=closed]:animate-out data-[state=closed]:fade-out-0 data-[state=open]:fade-in-0",
      className,
    )}
    {...props}
  />
));
DialogOverlay.displayName = DialogPrimitive.Overlay.displayName;

const DialogContent = React.forwardRef<
  React.ElementRef<typeof DialogPrimitive.Content>,
  React.ComponentPropsWithoutRef<typeof DialogPrimitive.Content>
>(({ className, children, ...props }, ref) => (
  <DialogPortal>
    <DialogOverlay />
    <DialogPrimitive.Content
      ref={ref}
      className={cn(
        "fixed left-[50%] top-[50%] z-50 grid w-full max-w-lg translate-x-[-50%] translate-y-[-50%] gap-4 border bg-background p-6 shadow-lg duration-200 data-[state=open]:animate-in data-[state=closed]:animate-out data-[state=closed]:fade-out-0 data-[state=open]:fade-in-0 data-[state=closed]:zoom-out-95 data-[state=open]:zoom-in-95 sm:rounded-lg",
        className,
      )}
      {...props}
    >
      {children}
      <DialogPrimitive.Close className="absolute right-4 top-4 rounded-sm opacity-70 ring-offset-background cursor-pointer transition-opacity hover:opacity-100 focus:outline-none focus:ring-2 focus:ring-ring focus:ring-offset-2 disabled:pointer-events-none data-[state=open]:bg-accent data-[state=open]:text-muted-foreground">
        <X className="h-4 w-4" />
        <span className="sr-only">Close</span>
      </DialogPrimitive.Close>
    </DialogPrimitive.Content>
  </DialogPortal>
));
DialogContent.displayName = DialogPrimitive.Content.displayName;

const DialogHeader = ({ className, ...props }: React.HTMLAttributes<HTMLDivElement>) => (
  <div className={cn("flex flex-col space-y-1.5 text-center sm:text-left", className)} {...props} />
);
DialogHeader.displayName = "DialogHeader";

const DialogFooter = ({ className, ...props }: React.HTMLAttributes<HTMLDivElement>) => (
  <div
    className={cn("flex flex-col-reverse sm:flex-row sm:justify-end sm:space-x-2", className)}
    {...props}
  />
);
DialogFooter.displayName = "DialogFooter";

const DialogTitle = React.forwardRef<
  React.ElementRef<typeof DialogPrimitive.Title>,
  React.ComponentPropsWithoutRef<typeof DialogPrimitive.Title>
>(({ className, ...props }, ref) => (
  <DialogPrimitive.Title
    ref={ref}
    className={cn("text-lg font-semibold leading-none tracking-tight", className)}
    {...props}
  />
));
DialogTitle.displayName = DialogPrimitive.Title.displayName;

const DialogDescription = React.forwardRef<
  React.ElementRef<typeof DialogPrimitive.Description>,
  React.ComponentPropsWithoutRef<typeof DialogPrimitive.Description>
>(({ className, ...props }, ref) => (
  <DialogPrimitive.Description
    ref={ref}
    className={cn("text-sm text-muted-foreground", className)}
    {...props}
  />
));
DialogDescription.displayName = DialogPrimitive.Description.displayName;

export {
  Dialog,
  DialogPortal,
  DialogOverlay,
  DialogTrigger,
  DialogClose,
  DialogContent,
  DialogHeader,
  DialogFooter,
  DialogTitle,
  DialogDescription,
};

import * as React from "react";
import { cva, type VariantProps } from "class-variance-authority";

import { cn } from "@/lib/utils";

const cardVariants = cva("text-card-foreground transition-shadow", {
  variants: {
    variant: {
      default: "rounded-3xl border bg-card shadow-card",
      elevated: "rounded-3xl border bg-card shadow-card hover:shadow-card-md",
      dark: "rounded-3xl border border-white/5 bg-brand-ink text-card-dark-foreground shadow-card-dark",
      glass: "rounded-3xl border border-white/40 bg-white/60 backdrop-blur shadow-card",
    },
  },
  defaultVariants: { variant: "default" },
});

export interface CardProps
  extends React.HTMLAttributes<HTMLDivElement>, VariantProps<typeof cardVariants> {}

const Card = React.forwardRef<HTMLDivElement, CardProps>(
  ({ className, variant, ...props }, ref) => (
    <div ref={ref} className={cn(cardVariants({ variant }), className)} {...props} />
  ),
);
Card.displayName = "Card";

const CardHeader = React.forwardRef<
  HTMLDivElement,
  React.HTMLAttributes<HTMLDivElement> & { action?: React.ReactNode }
>(({ className, action, children, ...props }, ref) => (
  <div ref={ref} className={cn("flex items-center justify-between p-5 pb-0", className)} {...props}>
    <div className="flex flex-col space-y-1.5">{children}</div>
    {action}
  </div>
));
CardHeader.displayName = "CardHeader";

const CardTitle = React.forwardRef<HTMLDivElement, React.HTMLAttributes<HTMLDivElement>>(
  ({ className, ...props }, ref) => (
    <div ref={ref} className={cn("text-lg font-semibold leading-none tracking-tight", className)} {...props} />
  ),
);
CardTitle.displayName = "CardTitle";

const CardDescription = React.forwardRef<HTMLDivElement, React.HTMLAttributes<HTMLDivElement>>(
  ({ className, ...props }, ref) => (
    <div ref={ref} className={cn("text-sm text-muted-foreground", className)} {...props} />
  ),
);
CardDescription.displayName = "CardDescription";

const CardContent = React.forwardRef<HTMLDivElement, React.HTMLAttributes<HTMLDivElement>>(
  ({ className, ...props }, ref) => (
    <div ref={ref} className={cn("p-5 pt-0", className)} {...props} />
  ),
);
CardContent.displayName = "CardContent";

const CardFooter = React.forwardRef<HTMLDivElement, React.HTMLAttributes<HTMLDivElement>>(
  ({ className, ...props }, ref) => (
    <div ref={ref} className={cn("flex items-center p-5 pt-0", className)} {...props} />
  ),
);
CardFooter.displayName = "CardFooter";

export { Card, CardHeader, CardFooter, CardTitle, CardDescription, CardContent, cardVariants };

import * as React from "react";
import { Slot } from "@radix-ui/react-slot";
import { cva, type VariantProps } from "class-variance-authority";

import { cn } from "@/lib/utils";

const buttonVariants = cva(
  "inline-flex items-center justify-center gap-2 whitespace-nowrap rounded-full text-sm font-medium cursor-pointer transition-colors focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2 disabled:pointer-events-none disabled:opacity-40 disabled:cursor-not-allowed [&_svg]:pointer-events-none [&_svg]:size-4 [&_svg]:shrink-0",
  {
    variants: {
      variant: {
        default: "bg-neutral-900 text-white hover:bg-neutral-700",
        yellow: "bg-primary text-primary-foreground hover:bg-primary/90",
        destructive: "bg-destructive text-destructive-foreground shadow-sm hover:bg-destructive/90",
        outline: "border border-border bg-background text-foreground hover:bg-muted",
        secondary: "bg-secondary text-secondary-foreground hover:bg-secondary/80",
        ghost: "text-muted-foreground hover:bg-muted hover:text-foreground",
        link: "text-primary underline-offset-4 hover:underline",
        icon: "border border-border bg-card text-muted-foreground shadow-card hover:bg-muted",
      },
      size: {
        default: "h-10 px-5",
        sm: "h-8 px-3 text-xs",
        lg: "h-12 px-8 text-base",
        icon: "h-11 w-11",
      },
    },
    defaultVariants: { variant: "default", size: "default" },
  },
);

export interface ButtonProps
  extends React.ButtonHTMLAttributes<HTMLButtonElement>, VariantProps<typeof buttonVariants> {
  asChild?: boolean;
}

const Button = React.forwardRef<HTMLButtonElement, ButtonProps>(
  ({ className, variant, size, asChild = false, ...props }, ref) => {
    const Comp = asChild ? Slot : "button";
    return (
      <Comp className={cn(buttonVariants({ variant, size, className }))} ref={ref} {...props} />
    );
  },
);
Button.displayName = "Button";

export { Button, buttonVariants };

import * as React from "react";

import { cn } from "@/lib/utils";

const Input = React.forwardRef<HTMLInputElement, React.ComponentProps<"input">>(
  ({ className, type, ...props }, ref) => (
    <input
      type={type}
      className={cn(
        "flex h-10 w-full rounded-xl border border-input bg-transparent px-3 py-2 text-base shadow-sm transition-colors file:border-0 file:bg-transparent file:text-sm file:font-medium file:text-foreground placeholder:text-muted-foreground focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring disabled:cursor-not-allowed disabled:opacity-50 md:text-sm",
        className,
      )}
      ref={ref}
      {...props}
    />
  ),
);
Input.displayName = "Input";

export { Input };

"use client";

import * as React from "react";
import * as LabelPrimitive from "@radix-ui/react-label";
import { cva, type VariantProps } from "class-variance-authority";

import { cn } from "@/lib/utils";

const labelVariants = cva(
  "text-sm font-medium leading-none peer-disabled:cursor-not-allowed peer-disabled:opacity-70",
);

const Label = React.forwardRef<
  React.ElementRef<typeof LabelPrimitive.Root>,
  React.ComponentPropsWithoutRef<typeof LabelPrimitive.Root> & VariantProps<typeof labelVariants>
>(({ className, ...props }, ref) => (
  <LabelPrimitive.Root ref={ref} className={cn(labelVariants(), className)} {...props} />
));
Label.displayName = LabelPrimitive.Root.displayName;

export { Label };

import * as React from "react";

import { Avatar, AvatarFallback, AvatarImage } from "@/components/ui/avatar";
import { cn } from "@/lib/utils";

export interface AvatarStackProps {
  avatars: Array<{ src?: string; alt: string; fallback: string }>;
  className?: string;
  size?: "sm" | "md";
}

function AvatarStack({ avatars, className, size = "sm" }: AvatarStackProps) {
  const sizeClass = size === "sm" ? "h-6 w-6" : "h-8 w-8";
  return (
    <div className={cn("flex -space-x-2 shrink-0", className)}>
      {avatars.map((a, i) => (
        <Avatar key={i} className={cn(sizeClass, "border-2 border-white")}>
          {a.src ? <AvatarImage src={a.src} alt={a.alt} /> : null}
          <AvatarFallback className="text-[10px]">{a.fallback}</AvatarFallback>
        </Avatar>
      ))}
    </div>
  );
}

export { AvatarStack };

"use client";

import * as React from "react";
import * as AvatarPrimitive from "@radix-ui/react-avatar";

import { cn } from "@/lib/utils";

const Avatar = React.forwardRef<
  React.ElementRef<typeof AvatarPrimitive.Root>,
  React.ComponentPropsWithoutRef<typeof AvatarPrimitive.Root>
>(({ className, ...props }, ref) => (
  <AvatarPrimitive.Root
    ref={ref}
    className={cn("relative flex h-10 w-10 shrink-0 overflow-hidden rounded-full", className)}
    {...props}
  />
));
Avatar.displayName = AvatarPrimitive.Root.displayName;

const AvatarImage = React.forwardRef<
  React.ElementRef<typeof AvatarPrimitive.Image>,
  React.ComponentPropsWithoutRef<typeof AvatarPrimitive.Image>
>(({ className, ...props }, ref) => (
  <AvatarPrimitive.Image
    ref={ref}
    className={cn("aspect-square h-full w-full", className)}
    {...props}
  />
));
AvatarImage.displayName = AvatarPrimitive.Image.displayName;

const AvatarFallback = React.forwardRef<
  React.ElementRef<typeof AvatarPrimitive.Fallback>,
  React.ComponentPropsWithoutRef<typeof AvatarPrimitive.Fallback>
>(({ className, ...props }, ref) => (
  <AvatarPrimitive.Fallback
    ref={ref}
    className={cn(
      "flex h-full w-full items-center justify-center rounded-full bg-muted",
      className,
    )}
    {...props}
  />
));
AvatarFallback.displayName = AvatarPrimitive.Fallback.displayName;

export { Avatar, AvatarImage, AvatarFallback };
